solution:
function countJewels(jewels, stones) {
  const set = new Set(jewels);
  let count = 0;
  for (let i = 0; i < stones.length; i++) if (set.has(stones[i])) count++;
  return count;
}

tests:
if (countJewels('aA', 'aAAbbbb') !== 3) throw new Error('mixed case');
if (countJewels('z', 'ZZ') !== 0) throw new Error('case sensitive');
if (countJewels('', 'abc') !== 0) throw new Error('no jewels');
if (countJewels('xyz', '') !== 0) throw new Error('no stones');

