solution:
function symmetricDiff(a, b) {
  const setA = new Set(a);
  const setB = new Set(b);
  const out = [];
  for (const x of setA) if (!setB.has(x)) out.push(x);
  for (const x of setB) if (!setA.has(x)) out.push(x);
  return out;
}

tests:
if (JSON.stringify(symmetricDiff([1, 2, 3], [2, 3, 4])) !== JSON.stringify([1, 4])) throw new Error('basic');
if (JSON.stringify(symmetricDiff([1, 1], [1])) !== JSON.stringify([])) throw new Error('all shared');
if (JSON.stringify(symmetricDiff([], [5])) !== JSON.stringify([5])) throw new Error('only b');

