function distinctCount(lists) {
  const all = new Set();
  for (let i = 0; i < lists.length; i++) { const lst = lists[i]; for (let j = 0; j < lst.length; j++) all.add(lst[j]); }
  return all.size;
}

tests:
if (distinctCount([[1, 2], [2, 3], [3, 4]]) !== 4) throw new Error('overlap');
if (distinctCount([]) !== 0) throw new Error('empty');
if (distinctCount([[5, 5], [5]]) !== 1) throw new Error('all same');
